def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            penalty = 0
            for n in range(1, 6):
                penalty += (ratio ** n) / (n * np.exp(n))
            priorities[i] = penalty + np.log1p(ratio ** 2)
        elif 1 < ratio <= 2:
            score = 0
            for k in range(1, 4):
                inner_sum = 0
                for m in range(1, k+1):
                    inner_sum += (ratio / m) ** m
                score += (inner_sum / k) * np.sin(np.pi * ratio / k)
            priorities[i] = score
        elif ratio == 1:
            priorities[i] = 1.0
        else:
            val = 0
            for power in range(1, 5):
                val += ((1 - ratio) ** power) / power
            if val == 0:
                priorities[i] = 0
            else:
                adjustment = 0
                for j in range(1, 4):
                    adjustment += np.cos(j * np.pi * ratio) / j
                priorities[i] = -np.log(val) + adjustment
    return priorities
